class Solution {
public:
    bool isSubsequence(string s, string t) {
        for (int i = 0; i < s.length(); i++) {
            if(t.find(s[i]) == std::string::npos){
                return false;
            }
        }
        return true;
    }
};

class Solution {
  public: bool isSubsequence(string s, string t) {
    int x = 0; int i = 0;
    while(i < s.length() && x < t.length()){
        if (s[i] == t[x]) {
                i++;
            }
            x++;
    }

return i == s.length();

  }

};
